function toNum(value, fallback = 0) {
  const num = Number(value);
  return Number.isFinite(num) ? num : fallback;
}

function pickFirstFiniteMetricValue(...values) {
  for (const value of values) {
    const num = Number(value);
    if (Number.isFinite(num) && num > 0) return num;
  }
  return 0;
}

function toFixed(value, digits = 2) {
  const num = toNum(value, NaN);
  if (!Number.isFinite(num)) return "0";
  return num.toFixed(digits);
}

function round(value, digits = 2) {
  const num = Number(value);
  if (!Number.isFinite(num)) return null;
  const scale = 10 ** digits;
  return Math.round(num * scale) / scale;
}

function toCompact(value) {
  const num = toNum(value, 0);
  const abs = Math.abs(num);
  if (abs >= 1e12) return `${toFixed(num / 1e12, 2)}T`;
  if (abs >= 1e9) return `${toFixed(num / 1e9, 2)}B`;
  if (abs >= 1e6) return `${toFixed(num / 1e6, 2)}M`;
  if (abs >= 1e3) return `${toFixed(num / 1e3, 2)}K`;
  return toFixed(num, 2);
}

function toTimestampMs(value) {
  const num = Number(value);
  if (!Number.isFinite(num) || num <= 0) return null;
  return num < 1e12 ? Math.round(num * 1000) : Math.round(num);
}

function cloneJson(value) {
  if (value === null || value === undefined) return value;
  return JSON.parse(JSON.stringify(value));
}

function calculatePositionUnrealizedPnlUsd({ entry = null, mark = null, size = null, side = null, fallback = 0 } = {}) {
  const entryNum = toNum(entry, NaN);
  const markNum = toNum(mark, NaN);
  const sizeNum = Math.abs(toNum(size, 0));
  if (Number.isFinite(entryNum) && Number.isFinite(markNum) && sizeNum > 0) {
    const sideText = String(side || "").trim().toLowerCase();
    const direction = sideText.includes("short") || sideText === "ask" || sideText === "sell" ? -1 : 1;
    return Number(((markNum - entryNum) * sizeNum * direction).toFixed(2));
  }
  return Number(toNum(fallback, 0).toFixed(2));
}

function calculateWalletEquityUsd({ exposureUsd = 0, realizedPnlUsd = 0, unrealizedPnlUsd = 0 } = {}) {
  const equity = toNum(exposureUsd, 0) + toNum(realizedPnlUsd, 0) + toNum(unrealizedPnlUsd, 0);
  return Math.max(1, equity);
}

function resolveMeaningfulMetric(value, fallback = null, minAbs = 0.005) {
  const candidate = Number(toNum(value, NaN));
  return Number.isFinite(candidate) && Math.abs(candidate) >= minAbs ? candidate : fallback;
}

function pickUnrealizedPnlUsdFromRow(row = {}) {
  const safeRow = row && typeof row === "object" ? row : {};
  const safeRaw = safeRow.raw && typeof safeRow.raw === "object" ? safeRow.raw : {};
  const candidates = [
    safeRow.unrealizedPnlUsd,
    safeRow.positionPnlUsd,
    safeRow.unrealizedPnl,
    safeRow.unrealized,
    safeRow.unrealizedUsd,
    safeRow.unrealized_usd,
    safeRow.unrealized_pnl_usd,
    safeRow.unrealized_pnl,
    safeRow.openPnl,
    safeRow.openPnL,
    safeRow.open_pnl,
    safeRow.pnl_open,
    safeRaw.unrealizedPnlUsd,
    safeRaw.positionPnlUsd,
    safeRaw.unrealizedPnl,
    safeRaw.unrealized,
    safeRaw.unrealizedUsd,
    safeRaw.unrealized_usd,
    safeRaw.unrealized_pnl_usd,
    safeRaw.unrealized_pnl,
    safeRaw.openPnl,
    safeRaw.openPnL,
    safeRaw.open_pnl,
    safeRaw.pnl_open,
  ];
  for (const candidate of candidates) {
    const num = toNum(candidate, NaN);
    if (Number.isFinite(num)) return num;
  }
  return NaN;
}

function pickUnrealizedPnlUsdFromSummary(summary = {}) {
  const safeSummary = summary && typeof summary === "object" ? summary : {};
  const safeRaw = safeSummary.raw && typeof safeSummary.raw === "object" ? safeSummary.raw : {};
  const safeAll = safeSummary.all && typeof safeSummary.all === "object" ? safeSummary.all : {};
  const candidates = [
    safeSummary.unrealizedPnlUsd,
    safeSummary.positionPnlUsd,
    safeSummary.unrealizedPnl,
    safeSummary.unrealized,
    safeSummary.unrealizedUsd,
    safeSummary.unrealized_usd,
    safeSummary.unrealized_pnl_usd,
    safeSummary.unrealized_pnl,
    safeSummary.openPnl,
    safeSummary.openPnL,
    safeSummary.open_pnl,
    safeSummary.pnl_open,
    safeAll.unrealizedPnlUsd,
    safeAll.positionPnlUsd,
    safeAll.unrealizedPnl,
    safeAll.unrealized,
    safeAll.unrealizedUsd,
    safeAll.unrealized_usd,
    safeAll.unrealized_pnl_usd,
    safeAll.unrealized_pnl,
    safeAll.openPnl,
    safeAll.openPnL,
    safeAll.open_pnl,
    safeAll.pnl_open,
    safeRaw.unrealizedPnlUsd,
    safeRaw.positionPnlUsd,
    safeRaw.unrealizedPnl,
    safeRaw.unrealized,
    safeRaw.unrealizedUsd,
    safeRaw.unrealized_usd,
    safeRaw.unrealized_pnl_usd,
    safeRaw.unrealized_pnl,
    safeRaw.openPnl,
    safeRaw.openPnL,
    safeRaw.open_pnl,
    safeRaw.pnl_open,
  ];
  for (const candidate of candidates) {
    const num = toNum(candidate, NaN);
    if (Number.isFinite(num)) return num;
  }
  return NaN;
}

function getPositionUnrealizedPnlUsd(row = {}) {
  const extracted = pickUnrealizedPnlUsdFromRow(row);
  return Number(
    toNum(extracted, 0).toFixed(2)
  );
}

function projectWalletFirstPositionRowForUi(row = {}) {
  const safeRow = row && typeof row === "object" ? row : {};
  const safeRaw = safeRow.raw && typeof safeRow.raw === "object" ? safeRow.raw : {};
  const wallet = String(safeRow.wallet || "").trim() || null;
  const symbol = String(safeRow.symbol || safeRow.token || "").trim().toUpperCase() || null;
  const side = String(safeRow.side || safeRow.rawSide || "").trim().toLowerCase() || null;
  const entryCandidate = Number(
    toNum(
      safeRow.entry !== undefined
        ? safeRow.entry
        : safeRow.entryPrice !== undefined
        ? safeRow.entryPrice
        : safeRow.entry_price !== undefined
        ? safeRow.entry_price
        : safeRow.price !== undefined
        ? safeRow.price
        : safeRow.mark,
      NaN
    )
  );
  const entry = Number.isFinite(entryCandidate) ? entryCandidate : null;
  const sizeCandidate = Number(
    toNum(
      safeRow.size !== undefined
        ? safeRow.size
        : safeRow.amount !== undefined
        ? safeRow.amount
        : safeRow.newSize !== undefined
        ? safeRow.newSize
        : safeRow.currentSize,
      NaN
    )
  );
  const size = Number.isFinite(sizeCandidate) ? sizeCandidate : null;
  const positionSize = Number.isFinite(Number(safeRow.positionUsd))
    ? Number(toNum(safeRow.positionUsd, 0))
    : Number.isFinite(Number(safeRow.positionSize))
    ? Number(toNum(safeRow.positionSize, 0))
    : Number.isFinite(sizeCandidate) && Number.isFinite(entryCandidate)
    ? Number(Math.abs(sizeCandidate * entryCandidate).toFixed(2))
    : size;
  const margin = Number(
    toNum(
      safeRow.margin !== undefined
        ? safeRow.margin
        : safeRow.marginUsd !== undefined
        ? safeRow.marginUsd
        : safeRow.margin_usd !== undefined
        ? safeRow.margin_usd
        : safeRaw.margin !== undefined
        ? safeRaw.margin
        : safeRaw.margin_usd,
      NaN
    )
  );
  const leverageCandidate = Number(
    toNum(
      safeRow.leverage !== undefined
        ? safeRow.leverage
        : safeRow.lev !== undefined
        ? safeRow.lev
        : safeRaw.leverage !== undefined
        ? safeRaw.leverage
        : safeRaw.lev !== undefined
        ? safeRaw.lev
        : Number.isFinite(margin) && margin > 0 && Number.isFinite(Number(positionSize))
        ? Math.abs(Number(positionSize)) / margin
        : NaN,
      NaN
    )
  );
  const leverage = Number.isFinite(leverageCandidate) ? leverageCandidate : null;
  const openedAt = Math.max(
    0,
    Number(safeRow.openedAt || 0),
    Number(safeRow.timestamp || 0),
    Number(safeRow.observedAt || 0)
  ) || null;
  const sideLabel =
    side === "open_short" || side === "short" || side === "ask"
      ? "short"
      : side === "open_long" || side === "long" || side === "bid"
      ? "long"
      : side;
  const eventType = safeRow.eventType ? String(safeRow.eventType).trim() || null : null;
  return {
    wallet,
    token: symbol,
    symbol,
    side: sideLabel,
    entry,
    size,
    positionSize,
    openedAt,
    positionKey: safeRow.positionKey || null,
    eventType,
    status: safeRow.status || null,
    oldSize: Number.isFinite(Number(safeRow.oldSize)) ? Number(toNum(safeRow.oldSize, 0)) : null,
    newSize: Number.isFinite(Number(safeRow.newSize)) ? Number(toNum(safeRow.newSize, 0)) : null,
    sizeDelta: Number.isFinite(Number(safeRow.sizeDelta)) ? Number(toNum(safeRow.sizeDelta, 0)) : null,
    sizeDeltaAbs: Number.isFinite(Number(safeRow.sizeDeltaAbs))
      ? Number(toNum(safeRow.sizeDeltaAbs, 0))
      : null,
    detectedAt: Number.isFinite(Number(safeRow.detectedAt))
      ? Number(toNum(safeRow.detectedAt, 0))
      : Number.isFinite(Number(safeRow.observedAt))
      ? Number(toNum(safeRow.observedAt, 0))
      : null,
    margin: Number.isFinite(margin) ? margin : null,
    leverage,
  };
}

function calculatePositionDrawdownPct(positionPnlUsd = 0, walletEquityUsd = 1) {
  const equity = Math.max(1, toNum(walletEquityUsd, 1));
  const lossUsd = Math.max(0, -toNum(positionPnlUsd, 0));
  return Number(((lossUsd / equity) * 100).toFixed(2));
}

function loadStrictLiveMonitorPayload() {
  return readJson(NEXTGEN_LIVE_MONITOR_PATH, { wallets: {} }) || { wallets: {} };
}

function getStrictLiveWalletState(wallet) {
  const normalizedWallet = String(wallet || "").trim();
  if (!normalizedWallet) return null;
  const payload = loadStrictLiveMonitorPayload();
  const wallets = payload && payload.wallets && typeof payload.wallets === "object" ? payload.wallets : {};
  const row = wallets[normalizedWallet];
  return row && typeof row === "object" ? row : null;
}

function hasPortfolioBackedWalletMetrics(row = {}) {
  const status = row && row.status && typeof row.status === "object" ? row.status : null;
  const metricSources =
    status && status.metricSources && typeof status.metricSources === "object"
      ? status.metricSources
      : null;
  return Boolean(
    metricSources &&
      metricSources.volumeUsd === "portfolio_volume" &&
      metricSources.pnlUsd === "portfolio_timeline" &&
      metricSources.drawdownPct === "portfolio_timeline" &&
      metricSources.returnPct === "portfolio_timeline" &&
      metricSources.accountEquityUsd === "portfolio_account" &&
      metricSources.openPositions === "portfolio_account"
  );
}

function resolveWalletTotalPnlUsd(row = {}) {
  const safeRow = row && typeof row === "object" ? row : {};
  const safeAll = safeRow.all && typeof safeRow.all === "object" ? safeRow.all : {};
  const candidates = [
    safeRow.totalPnlUsd,
    safeRow.totalPnl,
    safeRow.pnlUsd,
    safeRow.realizedPnlUsd,
    safeAll.totalPnlUsd,
    safeAll.totalPnl,
    safeAll.pnlUsd,
    safeAll.realizedPnlUsd,
    safeRow.pnlAllTime,
  ];
  for (const candidate of candidates) {
    const value = Number(toNum(candidate, NaN));
    if (Number.isFinite(value)) return Number(value.toFixed(2));
  }
  return NaN;
}

function isPositivePnlWalletRow(row = {}) {
  const totalPnlUsd = resolveWalletTotalPnlUsd(row);
  const safeRow = row && typeof row === "object" ? row : {};
  if (!Number.isFinite(totalPnlUsd) || totalPnlUsd <= 0) return false;
  const accountEquityUsd = Number(
    toNum(
      safeRow.accountEquityUsd !== undefined
        ? safeRow.accountEquityUsd
        : safeRow.all && safeRow.all.accountEquityUsd !== undefined
        ? safeRow.all.accountEquityUsd
        : NaN,
      NaN
    )
  );
  if (!Number.isFinite(accountEquityUsd) || accountEquityUsd <= 0) return false;
  const returnPct = Number(
    toNum(
      safeRow.returnPct !== undefined
        ? safeRow.returnPct
        : safeRow.all && safeRow.all.returnPct !== undefined
        ? safeRow.all.returnPct
        : NaN,
      NaN
    )
  );
  const lifecycleStage = String(
    safeRow.lifecycleStage || safeRow.lifecycle || safeRow.status || ""
  )
    .trim()
    .toLowerCase();
  return returnPct > 0 || lifecycleStage === "bootstrap";
}

function applyPortfolioMetricsToWalletRow(row = {}, detail = null) {
  const safeRow = row && typeof row === "object" ? row : {};
  const safeDetail = detail && typeof detail === "object" ? detail : null;
  if (!safeDetail) return safeRow;
  const safeStatus =
    safeRow.status && typeof safeRow.status === "object" ? { ...safeRow.status } : {};
  const metricSources =
    safeStatus.metricSources && typeof safeStatus.metricSources === "object"
      ? { ...safeStatus.metricSources }
      : {};
  const portfolioUnrealizedPnlUsd =
    resolveMeaningfulMetric(
      safeDetail.unrealizedPnlUsd ??
        safeDetail.unrealizedPnl ??
        safeDetail.unrealized_pnl ??
        safeDetail.positionPnlUsd ??
        safeDetail.pnlOpen,
      safeRow.unrealizedPnlUsd
    );
  const portfolioRealizedPnlUsd =
    safeDetail.pnlAllTime !== undefined && safeDetail.pnlAllTime !== null
      ? Number(toNum(safeDetail.pnlAllTime, safeRow.pnlUsd).toFixed(2))
      : safeRow.pnlUsd;
  const portfolioTotalPnlUsd =
    safeDetail.totalPnlUsd !== undefined && safeDetail.totalPnlUsd !== null
      ? Number(toNum(safeDetail.totalPnlUsd, safeRow.totalPnlUsd).toFixed(2))
      : safeDetail.totalPnl !== undefined && safeDetail.totalPnl !== null
      ? Number(toNum(safeDetail.totalPnl, safeRow.totalPnlUsd).toFixed(2))
      : safeDetail.pnlTotal !== undefined && safeDetail.pnlTotal !== null
      ? Number(toNum(safeDetail.pnlTotal, safeRow.totalPnlUsd).toFixed(2))
      : portfolioUnrealizedPnlUsd !== null
      ? Number((toNum(portfolioRealizedPnlUsd, 0) + toNum(portfolioUnrealizedPnlUsd, 0)).toFixed(2))
      : safeRow.totalPnlUsd;
  return {
    ...safeRow,
    volumeUsd:
      safeDetail.volumeAllTime !== undefined && safeDetail.volumeAllTime !== null
        ? Number(toNum(safeDetail.volumeAllTime, safeRow.volumeUsd).toFixed(2))
        : safeRow.volumeUsd,
    pnlUsd: portfolioRealizedPnlUsd,
    unrealizedPnlUsd:
      portfolioUnrealizedPnlUsd !== null ? portfolioUnrealizedPnlUsd : safeRow.unrealizedPnlUsd,
    totalPnlUsd: portfolioTotalPnlUsd,
    drawdownPct:
      safeDetail.drawdownPct !== undefined && safeDetail.drawdownPct !== null
        ? Number(toNum(safeDetail.drawdownPct, safeRow.drawdownPct).toFixed(2))
        : safeRow.drawdownPct,
    returnPct:
      safeDetail.returnPct !== undefined && safeDetail.returnPct !== null
        ? Number(toNum(safeDetail.returnPct, safeRow.returnPct).toFixed(2))
        : safeRow.returnPct,
    accountEquityUsd:
      safeDetail.accountEquityUsd !== undefined && safeDetail.accountEquityUsd !== null
        ? Number(toNum(safeDetail.accountEquityUsd, safeRow.accountEquityUsd).toFixed(2))
        : safeRow.accountEquityUsd,
    openPositions:
      safeDetail.openPositions !== undefined && safeDetail.openPositions !== null
        ? Math.max(0, Number(safeDetail.openPositions || 0))
        : safeRow.openPositions,
    status: {
      ...safeStatus,
      metricSources: {
        ...metricSources,
        volumeUsd: "portfolio_volume",
        pnlUsd: "portfolio_timeline",
        unrealizedPnlUsd: "portfolio_positions",
        totalPnlUsd: "portfolio_timeline_positions",
        drawdownPct: "portfolio_timeline",
        returnPct: "portfolio_timeline",
        accountEquityUsd: "portfolio_account",
        openPositions: "portfolio_account",
      },
      portfolioMetrics: {
        source: String(safeDetail.source || "portfolio_timeline_volume_account"),
        fetchedAt: Number(safeDetail.fetchedAt || 0) || null,
      },
    },
  };
}

function shouldHydratePortfolioMetricsForWalletRow(row = {}) {
  const safeRow = row && typeof row === "object" ? row : {};
  const wallet = String(safeRow.wallet || "").trim();
  if (!wallet || wallet.length < 24) return false;
  if (hasPortfolioBackedWalletMetrics(safeRow)) return false;
  const volumeUsd = Number(safeRow.volumeUsd || 0);
  const drawdownPct = safeRow.drawdownPct;
  const returnPct = safeRow.returnPct;
  const accountEquityUsd = safeRow.accountEquityUsd;
  const openPositions = safeRow.openPositions;
  return Boolean(
    volumeUsd > 0 ||
      drawdownPct === null ||
      drawdownPct === undefined ||
      returnPct === null ||
      returnPct === undefined ||
      accountEquityUsd === null ||
      accountEquityUsd === undefined ||
      openPositions === null ||
      openPositions === undefined
  );
}

async function hydrateWalletRowsWithPortfolioMetrics(rows = [], { maxFetch = 12, force = false } = {}) {
  const sourceRows = Array.isArray(rows) ? rows : [];
  if (!sourceRows.length) return sourceRows;
  const hydratedRows = sourceRows.slice();
  const targetIndexes = [];
  for (let index = 0; index < hydratedRows.length; index += 1) {
    if (shouldHydratePortfolioMetricsForWalletRow(hydratedRows[index])) {
      targetIndexes.push(index);
    }
    if (targetIndexes.length >= maxFetch) break;
  }
  if (!targetIndexes.length) return hydratedRows;
  const detailEntries = await Promise.all(
    targetIndexes.map((index) =>
      fetchPacificaPublicWalletDetail(hydratedRows[index] && hydratedRows[index].wallet, { force })
    )
  );
  targetIndexes.forEach((index, position) => {
    hydratedRows[index] = applyPortfolioMetricsToWalletRow(hydratedRows[index], detailEntries[position]);
  });
  return hydratedRows;
}

const walletExplorerIsolatedHistoryFeeCache = {
  wallet: null,
  mtimeMs: 0,
  payload: null,
};

const walletExplorerIsolatedOpenedAtCache = new Map();
const walletExplorerReviewRuntimeStatusCache = {
  mtimeMs: 0,
  value: new Map(),
};

function loadWalletExplorerIsolatedOpenedAt(wallet) {
  const normalizedWallet = String(wallet || "").trim();
  if (!normalizedWallet) return null;
  const filePath = path.join(
    WALLET_EXPLORER_ISOLATED_HISTORY_DIR,
    normalizedWallet,
    "wallet_history.json"
  );
  let mtimeMs = 0;
  try {
    mtimeMs = Math.max(0, Math.trunc(fs.statSync(filePath).mtimeMs || 0));
  } catch (_error) {
    mtimeMs = 0;
  }
  const cached = walletExplorerIsolatedOpenedAtCache.get(normalizedWallet);
  if (cached && cached.mtimeMs === mtimeMs) {
    return cached.openedAt;
  }
  let payload = null;
  try {
    payload = readJson(filePath, null);
  } catch (_error) {
    payload = null;
  }
  const trades = Array.isArray(payload && payload.trades) ? payload.trades : [];
  let lastOpenedAt = 0;
  for (const row of trades) {
    if (!row || typeof row !== "object") continue;
    const side = String(row.side || "").trim().toLowerCase();
    if (!side.startsWith("open_")) continue;
    const ts = Number(row.timestamp || row.created_at || row.createdAt || 0) || 0;
    if (ts > lastOpenedAt) lastOpenedAt = ts;
  }
  const openedAt = lastOpenedAt > 0 ? lastOpenedAt : null;
  walletExplorerIsolatedOpenedAtCache.set(normalizedWallet, { mtimeMs, openedAt });
  while (walletExplorerIsolatedOpenedAtCache.size > 8192) {
    const oldestKey = walletExplorerIsolatedOpenedAtCache.keys().next().value;
    if (!oldestKey) break;
    walletExplorerIsolatedOpenedAtCache.delete(oldestKey);
  }
  return openedAt;
}

function resolveWalletExplorerRowStoredOpenedAt(row = {}, bucket = null) {
  const safeRow = row && typeof row === "object" ? row : {};
  const safeBucket = bucket && typeof bucket === "object" ? bucket : null;
  return (
    Number(
      safeRow.lastOpenedAt ||
        safeRow.lastOpenedPosition?.openedAt ||
        safeRow.positionOpenedAt ||
        safeRow.lastPositionOpenedAt ||
        safeRow.lifecycle?.lastOpenedAt ||
        (safeBucket && safeBucket.lastOpenedAt) ||
        (safeRow.all && safeRow.all.lastOpenedAt) ||
        (safeRow.d30 && safeRow.d30.lastOpenedAt) ||
        (safeRow.d7 && safeRow.d7.lastOpenedAt) ||
        (safeRow.d24 && safeRow.d24.lastOpenedAt) ||
        0
    ) || null
  );
}

function shouldHydrateWalletExplorerOpenedAtFromIsolated(row = {}, bucket = null) {
  const safeRow = row && typeof row === "object" ? row : {};
  if (!String(safeRow.wallet || "").trim()) return false;
  if (resolveWalletExplorerRowStoredOpenedAt(safeRow, bucket)) return false;
  const activityAt =
    Number(safeRow.lastActivity || safeRow.lastActivityAt || safeRow.lastActiveAt || 0) || 0;
  const updatedAt = Number(safeRow.updatedAt || 0) || 0;
  return activityAt > 0 && updatedAt > 0 && activityAt === updatedAt;
}

function resolveWalletExplorerCanonicalOpenedAt(row = {}, bucket = null) {
  const storedOpenedAt = resolveWalletExplorerRowStoredOpenedAt(row, bucket);
  if (storedOpenedAt) return storedOpenedAt;
  if (!shouldHydrateWalletExplorerOpenedAtFromIsolated(row, bucket)) return null;
  return Number(loadWalletExplorerIsolatedOpenedAt(row && row.wallet) || 0) || null;
}

function loadWalletExplorerIsolatedHistoryFeeSummary(wallet) {
  const normalizedWallet = String(wallet || "").trim();
  if (!normalizedWallet) return null;
  const filePath = path.join(
    WALLET_EXPLORER_ISOLATED_HISTORY_DIR,
    normalizedWallet,
    "wallet_history.json"
  );
  let mtimeMs = 0;
  try {
    mtimeMs = Math.max(0, Math.trunc(fs.statSync(filePath).mtimeMs || 0));
  } catch (_error) {
    mtimeMs = 0;
  }
  if (
    walletExplorerIsolatedHistoryFeeCache.payload &&
    walletExplorerIsolatedHistoryFeeCache.wallet === normalizedWallet &&
    walletExplorerIsolatedHistoryFeeCache.mtimeMs > 0 &&
    walletExplorerIsolatedHistoryFeeCache.mtimeMs === mtimeMs
  ) {
    return walletExplorerIsolatedHistoryFeeCache.payload;
  }
  const payload = readJson(filePath, null);
  const trades = Array.isArray(payload && payload.trades) ? payload.trades : [];
  if (!trades.length) {
    walletExplorerIsolatedHistoryFeeCache.wallet = normalizedWallet;
    walletExplorerIsolatedHistoryFeeCache.mtimeMs = mtimeMs;
    walletExplorerIsolatedHistoryFeeCache.payload = null;
    return null;
  }
  let feesPaidUsd = 0;
  let liquidityPoolFeesUsd = 0;
  let netFeesUsd = 0;
  let firstTrade = null;
  let lastTrade = null;
  let firstOpenedAt = null;
  let lastOpenedAt = null;
  const isOpenSide = (side) => String(side || "").trim().toLowerCase().startsWith("open_");
  for (const row of trades) {
    if (!row || typeof row !== "object") continue;
    const ts = Number(row.timestamp || row.created_at || row.createdAt || 0);
    if (Number.isFinite(ts) && ts > 0) {
      firstTrade = firstTrade === null ? ts : Math.min(firstTrade, ts);
      lastTrade = lastTrade === null ? ts : Math.max(lastTrade, ts);
      if (isOpenSide(row.side)) {
        firstOpenedAt = firstOpenedAt === null ? ts : Math.min(firstOpenedAt, ts);
        lastOpenedAt = lastOpenedAt === null ? ts : Math.max(lastOpenedAt, ts);
      }
    }
    const fee = toNum(row.fee, 0);
    const liquidityPoolFee = Math.max(
      0,
      toNum(
        row.liquidityPoolFee !== undefined
          ? row.liquidityPoolFee
          : row.liquidity_pool_fee !== undefined
          ? row.liquidity_pool_fee
          : row.lp_fee !== undefined
          ? row.lp_fee
          : row.lpFee !== undefined
          ? row.lpFee
          : row.supply_side_fee !== undefined
          ? row.supply_side_fee
          : row.supplySideFee,
        0
      )
    );
    if (fee > 0) feesPaidUsd += fee;
    netFeesUsd += fee + liquidityPoolFee;
    liquidityPoolFeesUsd += liquidityPoolFee;
  }
  const summarized = {
    wallet: normalizedWallet,
    feesPaidUsd: Number(feesPaidUsd.toFixed(2)),
    feesUsd: Number(feesPaidUsd.toFixed(2)),
    liquidityPoolFeesUsd: Number(liquidityPoolFeesUsd.toFixed(2)),
    netFeesUsd: Number(netFeesUsd.toFixed(2)),
    firstTrade: firstTrade || null,
    lastTrade: lastTrade || null,
    firstOpenedAt: firstOpenedAt || null,
    lastOpenedAt: lastOpenedAt || null,
    source: "isolated_wallet_history",
    updatedAt: Number(payload && payload.updatedAt) || mtimeMs || null,
  };
  walletExplorerIsolatedHistoryFeeCache.wallet = normalizedWallet;
  walletExplorerIsolatedHistoryFeeCache.mtimeMs = mtimeMs;
  walletExplorerIsolatedHistoryFeeCache.payload = summarized;
  return summarized;
}

