function buildMarketPriceLookup(pricesBySymbol = {}) {
  const lookup = new Map();
  if (Array.isArray(pricesBySymbol)) {
    pricesBySymbol.forEach((value) => {
      const row = value && typeof value === "object" ? value : {};
      const normalized = String(row.symbol || "").trim().toUpperCase();
      if (!normalized) return;
      const mark = toNum(
        row.mark !== undefined
          ? row.mark
          : row.markPrice !== undefined
          ? row.markPrice
          : row.mid !== undefined
          ? row.mid
          : row.price,
        NaN
      );
      if (!Number.isFinite(mark) || mark <= 0) return;
      lookup.set(normalized, mark);
    });
    return lookup;
  }
  const source =
    pricesBySymbol && typeof pricesBySymbol === "object" ? pricesBySymbol : {};
  Object.entries(source).forEach(([symbol, value]) => {
    const normalized = String(symbol || "").trim().toUpperCase();
    if (!normalized) return;
    const row = value && typeof value === "object" ? value : {};
    const mark = toNum(
      row.mark !== undefined
        ? row.mark
        : row.markPrice !== undefined
        ? row.markPrice
        : row.mid !== undefined
        ? row.mid
        : row.price,
      NaN
    );
    if (!Number.isFinite(mark) || mark <= 0) return;
    lookup.set(normalized, mark);
  });
  return lookup;
}

function enrichPositionRowWithMarketPrice(row = {}, priceLookup = null) {
  const safeRow = row && typeof row === "object" ? row : {};
  const lookup = priceLookup instanceof Map ? priceLookup : null;
  const readMaybeNumber = (value) => {
    if (value === null || value === undefined || value === "") return NaN;
    const num = Number(value);
    return Number.isFinite(num) ? num : NaN;
  };
  const symbol = String(safeRow.symbol || "").trim().toUpperCase();
  const entry = readMaybeNumber(
    safeRow.entry !== undefined
      ? safeRow.entry
      : safeRow.entryPrice !== undefined
      ? safeRow.entryPrice
      : safeRow.entry_price !== undefined
      ? safeRow.entry_price
      : safeRow.raw && safeRow.raw.entry_price !== undefined
      ? safeRow.raw.entry_price
      : NaN
  );
  const existingMark = readMaybeNumber(
    safeRow.mark !== undefined
      ? safeRow.mark
      : safeRow.markPrice !== undefined
      ? safeRow.markPrice
      : safeRow.mark_price !== undefined
      ? safeRow.mark_price
      : safeRow.currentPrice !== undefined
      ? safeRow.currentPrice
      : safeRow.raw && safeRow.raw.mark_price !== undefined
      ? safeRow.raw.mark_price
      : NaN
  );
  const marketMark = symbol && lookup ? toNum(lookup.get(symbol), NaN) : NaN;
  const rawPnlInput = pickUnrealizedPnlUsdFromRow(safeRow);
  const hasExplicitPnl = Number.isFinite(readMaybeNumber(rawPnlInput));
  const mark =
    Number.isFinite(marketMark) &&
    (
      !Number.isFinite(existingMark) ||
      !hasExplicitPnl ||
      (Number.isFinite(entry) && Math.abs(existingMark - entry) <= 1e-12)
    )
      ? marketMark
      : existingMark;
  const size = Math.abs(
    readMaybeNumber(
      safeRow.size !== undefined
        ? safeRow.size
        : safeRow.amount !== undefined
        ? safeRow.amount
        : safeRow.qty !== undefined
        ? safeRow.qty
        : safeRow.raw && safeRow.raw.amount !== undefined
        ? safeRow.raw.amount
        : NaN
    )
  );
  let pnl = readMaybeNumber(rawPnlInput);
  const shouldRecalculatePnl =
    Number.isFinite(entry) &&
    Number.isFinite(mark) &&
    Number.isFinite(size) &&
    (
      !Number.isFinite(pnl) ||
      (Number.isFinite(marketMark) &&
        Number.isFinite(mark) &&
        (!Number.isFinite(existingMark) || Math.abs(mark - existingMark) > 1e-12))
    );
  if (shouldRecalculatePnl) {
    const sideRaw = String(safeRow.side || safeRow.rawSide || "").trim().toLowerCase();
    const direction =
      sideRaw.includes("short") || sideRaw === "ask" || sideRaw === "short" ? -1 : 1;
    pnl = (mark - entry) * size * direction;
  }
  const positionUsd =
    Number.isFinite(mark) && Number.isFinite(size)
      ? Math.abs(mark * size)
      : toNum(
          safeRow.positionUsd !== undefined
            ? safeRow.positionUsd
            : safeRow.notionalUsd !== undefined
            ? safeRow.notionalUsd
            : NaN,
          NaN
        );
  return {
    ...safeRow,
    mark: Number.isFinite(mark) ? Number(mark.toFixed(8)) : safeRow.mark,
    pnl: Number.isFinite(pnl) ? Number(pnl.toFixed(2)) : safeRow.pnl,
    unrealizedPnlUsd: Number.isFinite(pnl)
      ? Number(pnl.toFixed(2))
      : safeRow.unrealizedPnlUsd,
    positionUsd: Number.isFinite(positionUsd)
      ? Number(positionUsd.toFixed(2))
      : safeRow.positionUsd,
  };
}

function computeDefiLlamaV2FromPrices(rows = []) {
  return (Array.isArray(rows) ? rows : []).reduce(
    (acc, item) => {
      const reportedVolume24h = toNum(
        item && item.volume_24h !== undefined ? item.volume_24h : 0
      );
      // Pacifica reports both taker and maker sides in its volume-style fields.
      // DeFiLlama's Pacifica adapter compensates for that by halving kline-based volume.
      // We apply the same correction to rolling 24h volume rows from /info/prices.
      const volume24h = reportedVolume24h / 2;
      const openInterest = toNum(
        item && item.open_interest !== undefined ? item.open_interest : 0
      );
      const mark = toNum(item && item.mark !== undefined ? item.mark : 0);

      acc.dailyVolume += volume24h;
      acc.openInterestAtEnd += openInterest * mark;
      return acc;
    },
    {
      dailyVolume: 0,
      openInterestAtEnd: 0,
    }
  );
}

function buildDefiLlamaVolumeRank(rows = [], limit = 100) {
  return (Array.isArray(rows) ? rows : [])
    .map((item) => {
      const symbolRaw = item && item.symbol !== undefined ? item.symbol : "";
      const symbol = String(symbolRaw || "").trim();
      const reportedVolume24h = toNum(
        item && item.volume_24h !== undefined ? item.volume_24h : 0
      );
      const volume24h = reportedVolume24h / 2;
      const openInterest = toNum(
        item && item.open_interest !== undefined ? item.open_interest : 0
      );
      const mark = toNum(item && item.mark !== undefined ? item.mark : 0);
      const openInterestUsd = openInterest * mark;

      return {
        symbol,
        volume_24h_usd: Number(volume24h.toFixed(8)),
        volume_usd: Number(volume24h.toFixed(8)),
        open_interest_usd: Number(openInterestUsd.toFixed(8)),
        openInterestUsd: Number(openInterestUsd.toFixed(8)),
        open_interest: Number(openInterest.toFixed(8)),
        openInterest: Number(openInterest.toFixed(8)),
        mark: Number(mark.toFixed(8)),
        markPrice: Number(mark.toFixed(8)),
      };
    })
    .filter((row) => Boolean(row.symbol))
    .sort((a, b) => toNum(b.volume_24h_usd, 0) - toNum(a.volume_24h_usd, 0))
    .slice(0, Math.max(1, Number(limit || 100)))
    .map((row, idx) => ({
      rank: idx + 1,
      symbol: row.symbol,
      market: row.symbol,
      volume_24h_usd: row.volume_24h_usd,
      volume_usd: row.volume_usd,
      open_interest_usd: row.open_interest_usd,
      openInterestUsd: row.openInterestUsd,
      open_interest: row.open_interest,
      openInterest: row.openInterest,
      mark: row.mark,
      markPrice: row.markPrice,
      volumeUsd: toFixed(row.volume_24h_usd, 2),
      volumeCompact: (() => {
        const value = toNum(row.volume_24h_usd, 0);
        const abs = Math.abs(value);
        if (abs >= 1e12) return `${toFixed(value / 1e12, 2)}T`;
        if (abs >= 1e9) return `${toFixed(value / 1e9, 2)}B`;
        if (abs >= 1e6) return `${toFixed(value / 1e6, 2)}M`;
        if (abs >= 1e3) return `${toFixed(value / 1e3, 2)}K`;
        return toFixed(value, 2);
      })(),
      live: true,
    }));
}

function formatUtcDateFromMs(ms) {
  const n = Number(ms);
  if (!Number.isFinite(n)) return null;
  return new Date(n).toISOString().slice(0, 10);
}

function addUtcDays(dateStr, deltaDays) {
  const base = Date.parse(`${String(dateStr).slice(0, 10)}T00:00:00.000Z`);
  if (!Number.isFinite(base)) return null;
  return formatUtcDateFromMs(base + Number(deltaDays || 0) * 24 * 60 * 60 * 1000);
}

function buildHistoricalSymbolVolumeRank({
  dailyByDate = null,
  startDate = null,
  endDate = null,
  limit = 100,
  requireReliableDay = true,
  priceRows = [],
}) {
  if (!dailyByDate || typeof dailyByDate !== "object") return [];
  const safeEndDate =
    endDate && String(endDate).trim() ? String(endDate).slice(0, 10) : null;
  if (!safeEndDate) return [];
  const safeStartDate =
    startDate && String(startDate).trim() ? String(startDate).slice(0, 10) : null;

  const volumeBySymbol = new Map();
  const entries = Object.entries(dailyByDate);
  for (const [dayRaw, dayRowRaw] of entries) {
    const day = String(dayRaw || "").slice(0, 10);
    if (!day) continue;
    if (safeStartDate && day < safeStartDate) continue;
    if (day > safeEndDate) continue;
    const dayRow = dayRowRaw && typeof dayRowRaw === "object" ? dayRowRaw : {};
    const failedSymbols = Number(dayRow.failedSymbols || 0);
    if (requireReliableDay && Number.isFinite(failedSymbols) && failedSymbols > 0) continue;
    const symbolVolumes =
      dayRow.symbolVolumes && typeof dayRow.symbolVolumes === "object"
        ? dayRow.symbolVolumes
        : {};
    Object.entries(symbolVolumes).forEach(([symbolRaw, valueRaw]) => {
      const symbol = String(symbolRaw || "").trim();
      if (!symbol) return;
      const volume = toNum(valueRaw, 0);
      if (!Number.isFinite(volume) || volume <= 0) return;
      volumeBySymbol.set(symbol, (volumeBySymbol.get(symbol) || 0) + volume);
    });
  }

  return Array.from(volumeBySymbol.entries())
    .map(([symbol, volume]) => {
      const priceRow = findPriceRowForSymbol(priceRows, symbol);
      const mark = toNum(
        priceRow && priceRow.mark !== undefined
          ? priceRow.mark
          : priceRow && priceRow.markPrice !== undefined
          ? priceRow.markPrice
          : NaN,
        NaN
      );
      const openInterest = toNum(
        priceRow && priceRow.open_interest !== undefined
          ? priceRow.open_interest
          : priceRow && priceRow.openInterest !== undefined
          ? priceRow.openInterest
          : NaN,
        NaN
      );
      const openInterestUsd =
        Number.isFinite(mark) && Number.isFinite(openInterest) && openInterest > 0 && mark > 0
          ? openInterest * mark
          : NaN;
      return {
        symbol,
        volume_usd: Number(volume.toFixed(8)),
        open_interest_usd: Number.isFinite(openInterestUsd)
          ? Number(openInterestUsd.toFixed(8))
          : null,
        openInterestUsd: Number.isFinite(openInterestUsd)
          ? Number(openInterestUsd.toFixed(8))
          : null,
        open_interest: Number.isFinite(openInterest)
          ? Number(openInterest.toFixed(8))
          : null,
        openInterest: Number.isFinite(openInterest)
          ? Number(openInterest.toFixed(8))
          : null,
        mark: Number.isFinite(mark) ? Number(mark.toFixed(8)) : null,
        markPrice: Number.isFinite(mark) ? Number(mark.toFixed(8)) : null,
      };
    })
    .sort((a, b) => toNum(b.volume_usd, 0) - toNum(a.volume_usd, 0))
    .slice(0, Math.max(1, Number(limit || 100)))
    .map((row, idx) => ({
      rank: idx + 1,
      symbol: row.symbol,
      market: row.symbol,
      volume_usd: row.volume_usd,
      // Kept for UI backward compatibility (table renderer checks this key first).
      volume_24h_usd: row.volume_usd,
      open_interest_usd: row.open_interest_usd,
      openInterestUsd: row.openInterestUsd,
      open_interest: row.open_interest,
      openInterest: row.openInterest,
      mark: row.mark,
      markPrice: row.markPrice,
      volumeUsd: toFixed(row.volume_usd, 2),
      volumeCompact: toCompact(row.volume_usd),
      live: true,
    }));
}

function countHistoricalDaysWithSymbolVolumes({
  dailyByDate = null,
  startDate = null,
  endDate = null,
  requireReliableDay = true,
}) {
  if (!dailyByDate || typeof dailyByDate !== "object") return 0;
  const safeEndDate =
    endDate && String(endDate).trim() ? String(endDate).slice(0, 10) : null;
  if (!safeEndDate) return 0;
  const safeStartDate =
    startDate && String(startDate).trim() ? String(startDate).slice(0, 10) : null;
  let days = 0;
  Object.entries(dailyByDate).forEach(([dayRaw, rowRaw]) => {
    const day = String(dayRaw || "").slice(0, 10);
    if (!day) return;
    if (safeStartDate && day < safeStartDate) return;
    if (day > safeEndDate) return;
    const row = rowRaw && typeof rowRaw === "object" ? rowRaw : {};
    const failedSymbols = Number(row.failedSymbols || 0);
    if (requireReliableDay && Number.isFinite(failedSymbols) && failedSymbols > 0) return;
    const volumes =
      row.symbolVolumes && typeof row.symbolVolumes === "object"
        ? row.symbolVolumes
        : null;
    if (!volumes || Array.isArray(volumes)) return;
    if (Object.keys(volumes).length <= 0) return;
    days += 1;
  });
  return days;
}

function sumRankVolumeUsd(rows = []) {
  return (Array.isArray(rows) ? rows : []).reduce((acc, row) => {
    const raw =
      row && row.volume_24h_usd !== undefined ? row.volume_24h_usd : row && row.volume_usd;
    return acc + toNum(raw, 0);
  }, 0);
}

function buildHistoricalSymbolVolumeSnapshot({
  dailyByDate = null,
  startDate = null,
  endDate = null,
  requireReliableDay = false,
}) {
  if (!dailyByDate || typeof dailyByDate !== "object") {
    return { symbolVolumeMap: new Map(), totalVolumeUsd: 0 };
  }
  const safeEndDate =
    endDate && String(endDate).trim() ? String(endDate).slice(0, 10) : null;
  if (!safeEndDate) return { symbolVolumeMap: new Map(), totalVolumeUsd: 0 };
  const safeStartDate =
    startDate && String(startDate).trim() ? String(startDate).slice(0, 10) : null;
  const symbolVolumeMap = new Map();
  let totalVolumeUsd = 0;
  Object.entries(dailyByDate).forEach(([dayRaw, rowRaw]) => {
    const day = String(dayRaw || "").slice(0, 10);
    if (!day) return;
    if (safeStartDate && day < safeStartDate) return;
    if (day > safeEndDate) return;
    const row = rowRaw && typeof rowRaw === "object" ? rowRaw : {};
    const failedSymbols = Number(row.failedSymbols || 0);
    if (requireReliableDay && Number.isFinite(failedSymbols) && failedSymbols > 0) return;
    const symbolVolumes =
      row.symbolVolumes && typeof row.symbolVolumes === "object" && !Array.isArray(row.symbolVolumes)
        ? row.symbolVolumes
        : null;
    if (!symbolVolumes) return;
    Object.entries(symbolVolumes).forEach(([symbolRaw, valueRaw]) => {
      const symbol = String(symbolRaw || "").trim();
      if (!symbol) return;
      const volume = toNum(valueRaw, 0);
      if (!Number.isFinite(volume) || volume <= 0) return;
      symbolVolumeMap.set(symbol, (symbolVolumeMap.get(symbol) || 0) + volume);
      totalVolumeUsd += volume;
    });
  });
  return {
    symbolVolumeMap,
    totalVolumeUsd: Number(totalVolumeUsd.toFixed(8)),
  };
}

function buildVolumeRankRowsWithShareMetrics(
  rows = [],
  { totalVolumeUsd = 0, previousSymbolVolumeMap = null, previousTotalVolumeUsd = 0 } = {}
) {
  const priorMap =
    previousSymbolVolumeMap instanceof Map
      ? previousSymbolVolumeMap
      : previousSymbolVolumeMap && typeof previousSymbolVolumeMap === "object"
      ? new Map(Object.entries(previousSymbolVolumeMap))
      : new Map();
  const safeTotalVolumeUsd = Math.max(0, Number(totalVolumeUsd || 0));
  const safePreviousTotalVolumeUsd = Math.max(0, Number(previousTotalVolumeUsd || 0));
  return (Array.isArray(rows) ? rows : []).map((row) => {
    const symbol = String((row && (row.symbol || row.market)) || "").trim();
    const volume = toNum(
      row && row.volume_24h_usd !== undefined ? row.volume_24h_usd : row && row.volume_usd,
      0
    );
    const sharePct = safeTotalVolumeUsd > 0 ? (volume / safeTotalVolumeUsd) * 100 : 0;
    const previousVolume = toNum(priorMap.get(symbol), 0);
    const previousSharePct =
      safePreviousTotalVolumeUsd > 0 ? (previousVolume / safePreviousTotalVolumeUsd) * 100 : null;
    const shareChange24hPct =
      previousSharePct === null ? null : Number((sharePct - previousSharePct).toFixed(4));
    const shareDirection =
      shareChange24hPct === null
        ? "flat"
        : shareChange24hPct > 0.0001
        ? "up"
        : shareChange24hPct < -0.0001
        ? "down"
        : "flat";
    return {
      ...row,
      sharePct: Number(sharePct.toFixed(4)),
      previousSharePct:
        previousSharePct === null ? null : Number(previousSharePct.toFixed(4)),
      shareChange24hPct,
      shareDirection,
    };
  });
}

const KPI_DAY_MS = 24 * 60 * 60 * 1000;
  const EXCHANGE_DAILY_SERIES_POINTS = 24;
  const EXCHANGE_WEEKLY_SERIES_POINTS = 7;
  const EXCHANGE_MONTHLY_SERIES_POINTS = 30;

function pickWalletWindowBucket(record = {}, timeframe = "all") {
  const safeRecord = record && typeof record === "object" ? record : {};
  if (timeframe === "24h") return safeRecord.d24 || null;
  if (timeframe === "7d") return safeRecord.d7 || null;
  if (timeframe === "30d") return safeRecord.d30 || null;
  return safeRecord.all || safeRecord || null;
}

function aggregateWalletWindowMetrics(walletRecords = [], timeframe = "all") {
  const rows = Array.isArray(walletRecords) ? walletRecords : [];
  let totalTrades = 0;
  let totalVolumeUsd = 0;
  let totalFeesUsd = 0;
  let activeAccounts = 0;

  rows.forEach((record) => {
    const bucket = pickWalletWindowBucket(record, timeframe);
    if (!bucket || typeof bucket !== "object") return;

    const trades = toNum(bucket.trades, 0);
    const volumeUsd = toNum(bucket.volumeUsd, 0);
    const feesPaid = toNum(
      bucket.feesPaidUsd !== undefined ? bucket.feesPaidUsd : bucket.feesUsd,
      0
    );
    const liquidityPoolFeesUsd = toNum(bucket.liquidityPoolFeesUsd, 0);

    totalTrades += trades;
    totalVolumeUsd += volumeUsd;
    totalFeesUsd += feesPaid + liquidityPoolFeesUsd;

    if (trades > 0 || volumeUsd > 0 || feesPaid > 0 || liquidityPoolFeesUsd > 0) {
      activeAccounts += 1;
    }
  });

  return {
    totalAccounts: rows.length,
    activeAccounts,
    totalTrades,
    totalVolumeUsd,
    totalFeesUsd,
  };
}

function computeWalletCoverageDays(walletRecords = []) {
  const rows = Array.isArray(walletRecords) ? walletRecords : [];
  let minFirstTrade = Infinity;
  let maxLastTrade = 0;

  rows.forEach((record) => {
    const bucket =
      record && typeof record === "object"
        ? record.all && typeof record.all === "object"
          ? record.all
          : record
        : null;
    if (!bucket) return;
    const firstTrade = toNum(bucket.firstTrade, NaN);
    const lastTrade = toNum(bucket.lastTrade, NaN);
    if (Number.isFinite(firstTrade) && firstTrade > 0) {
      minFirstTrade = Math.min(minFirstTrade, firstTrade);
    }
    if (Number.isFinite(lastTrade) && lastTrade > 0) {
      maxLastTrade = Math.max(maxLastTrade, lastTrade);
    }
  });

  if (!Number.isFinite(minFirstTrade) || !Number.isFinite(maxLastTrade) || maxLastTrade < minFirstTrade) {
    return null;
  }

  return Math.max(1, Math.floor((maxLastTrade - minFirstTrade) / KPI_DAY_MS) + 1);
}

function computeWalletCoverageWindow(walletRecords = []) {
  const rows = Array.isArray(walletRecords) ? walletRecords : [];
  let minFirstTrade = Infinity;
  let maxLastTrade = 0;
  let walletsWithHistory = 0;
  let walletsWithTrades = 0;
  let walletsWithFees = 0;

  rows.forEach((record) => {
    const bucket =
      record && typeof record === "object"
        ? record.all && typeof record.all === "object"
          ? record.all
          : record
        : null;
    if (!bucket) return;
    const firstTrade = toNum(bucket.firstTrade, NaN);
    const lastTrade = toNum(bucket.lastTrade, NaN);
    const trades = toNum(bucket.trades, 0);
    const fees = toNum(
      bucket.feesPaidUsd !== undefined ? bucket.feesPaidUsd : bucket.feesUsd,
      0
    );

    if (
      (Number.isFinite(firstTrade) && firstTrade > 0) ||
      (Number.isFinite(lastTrade) && lastTrade > 0) ||
      trades > 0
    ) {
      walletsWithHistory += 1;
    }
    if (trades > 0) walletsWithTrades += 1;
    if (Math.abs(fees) > 0) walletsWithFees += 1;

    if (Number.isFinite(firstTrade) && firstTrade > 0) {
      minFirstTrade = Math.min(minFirstTrade, firstTrade);
    }
    if (Number.isFinite(lastTrade) && lastTrade > 0) {
      maxLastTrade = Math.max(maxLastTrade, lastTrade);
    }
  });

  return {
    startMs: Number.isFinite(minFirstTrade) ? minFirstTrade : null,
    endMs: Number.isFinite(maxLastTrade) && maxLastTrade > 0 ? maxLastTrade : null,
    startDate: Number.isFinite(minFirstTrade) ? formatUtcDateFromMs(minFirstTrade) : null,
    endDate:
      Number.isFinite(maxLastTrade) && maxLastTrade > 0 ? formatUtcDateFromMs(maxLastTrade) : null,
    walletsWithHistory,
    walletsWithTrades,
    walletsWithFees,
  };
}

function resolveExchangeWalletMetricValues({
  timeframe = "all",
  walletMetricHistorySnapshot = null,
  walletMetricDailyByDate = {},
  walletMetricTrackedThroughDate = null,
  walletWindowMetrics = null,
  walletExplorerRows = [],
} = {}) {
  const dailyByDate =
    walletMetricDailyByDate && typeof walletMetricDailyByDate === "object"
      ? walletMetricDailyByDate
      : {};
  const coverage =
    walletMetricHistorySnapshot &&
    walletMetricHistorySnapshot.coverage &&
    typeof walletMetricHistorySnapshot.coverage === "object"
      ? walletMetricHistorySnapshot.coverage
      : {};
  const trackedThroughDate =
    walletMetricTrackedThroughDate && String(walletMetricTrackedThroughDate).trim()
      ? String(walletMetricTrackedThroughDate).slice(0, 10)
      : coverage.endDate
      ? String(coverage.endDate).slice(0, 10)
      : getLastDateKeyFromDateMap(dailyByDate);
  const trackedThroughRow =
    trackedThroughDate && dailyByDate[trackedThroughDate] ? dailyByDate[trackedThroughDate] : null;
  const thirtyDayStart = trackedThroughDate ? addUtcDays(trackedThroughDate, -29) : null;
  const walletRows = Array.isArray(walletExplorerRows) ? walletExplorerRows : [];
  const activeWalletsLookbackDays = timeframe === "30d" ? 30 : timeframe === "24h" ? 1 : 0;
  const activeWalletsLookbackValue =
    activeWalletsLookbackDays > 0
      ? countWalletsWithActivityInLookback(walletRows, trackedThroughDate, activeWalletsLookbackDays)
      : 0;
  const activeWalletsCurrent24hValue = pickFirstFiniteMetricValue(
    walletWindowMetrics && walletWindowMetrics["24h"]
      ? walletWindowMetrics["24h"].activeAccounts
      : 0,
    countWalletsWithActivityInLookback(walletRows, trackedThroughDate, 1),
    trackedThroughRow && trackedThroughRow.activeWallets,
    trackedThroughDate
      ? resolveDailyMetricValueAtDate(dailyByDate, trackedThroughDate, (row) =>
          row && row.activeWallets !== undefined ? row.activeWallets : row && row.value
        )
      : 0
  );

  const activeWalletsValue = pickFirstFiniteMetricValue(
    timeframe === "30d"
      ? countWalletsWithActivityInLookback(walletRows, trackedThroughDate, 30)
      : activeWalletsCurrent24hValue,
    timeframe === "30d"
      ? countWalletsWithActivityInLookback(walletRows, trackedThroughDate, 30)
      : trackedThroughRow && trackedThroughRow.activeWallets,
    activeWalletsLookbackValue
  );

  const totalTradesValue = pickFirstFiniteMetricValue(
    timeframe === "24h"
      ? walletWindowMetrics && walletWindowMetrics["24h"]
        ? walletWindowMetrics["24h"].totalTrades
        : resolveDailyMetricValueAtDate(dailyByDate, trackedThroughDate, (row) =>
            row && row.trades !== undefined ? row.trades : 0
          )
      : timeframe === "30d"
      ? sumDailyMetricRange(
          dailyByDate,
          thirtyDayStart,
          trackedThroughDate,
          (row) => (row && row.trades !== undefined ? row.trades : 0)
        )
      : Number(coverage.totalTrades || 0),
    walletWindowMetrics && walletWindowMetrics[timeframe]
      ? walletWindowMetrics[timeframe].totalTrades
      : 0
  );

  const totalFeesValue = pickFirstFiniteMetricValue(
    timeframe === "24h"
      ? walletWindowMetrics && walletWindowMetrics["24h"]
        ? walletWindowMetrics["24h"].totalFeesUsd
        : trackedThroughRow && trackedThroughRow.feesUsd
      : timeframe === "30d"
      ? sumDailyMetricRange(
          dailyByDate,
          thirtyDayStart,
          trackedThroughDate,
          (row) => (row && row.feesUsd !== undefined ? row.feesUsd : 0)
        )
      : Number(coverage.totalFeesUsd || 0),
    walletWindowMetrics && walletWindowMetrics[timeframe]
      ? walletWindowMetrics[timeframe].totalFeesUsd
      : 0
  );

  return {
    activeWalletsValue,
    totalTradesValue,
    totalFeesValue,
    trackedThroughDate,
    trackedThroughRow,
    thirtyDayStart,
  };
}

function countWalletsWithActivityInLookback(walletRows = [], trackedThroughDate = null, lookbackDays = 30) {
  if (!trackedThroughDate) return 0;
  const endMs = Date.parse(`${String(trackedThroughDate).slice(0, 10)}T23:59:59.999Z`);
  const startMs = addUtcDays(String(trackedThroughDate).slice(0, 10), -(Math.max(1, Number(lookbackDays || 30)) - 1));
  const startDateMs = Date.parse(`${String(startMs).slice(0, 10)}T00:00:00.000Z`);
  if (!Number.isFinite(endMs) || !Number.isFinite(startDateMs)) return 0;
  let count = 0;
  for (const row of Array.isArray(walletRows) ? walletRows : []) {
    if (!row || typeof row !== "object") continue;
    const activityMs = Number(
      row.lastTrade ||
        row.lastActivity ||
        row.lastActivityAt ||
        (row.all &&
          (row.all.lastTrade ||
            row.all.lastActivity ||
            row.all.lastActivityAt)) ||
        row.updatedAt ||
        row.lastOpenedAt ||
        row.lastOpenedPositionAt ||
        row.lastPositionOpenedAt ||
        row.positionOpenedAt ||
        0
    );
    if (!Number.isFinite(activityMs) || activityMs <= 0) continue;
    if (activityMs >= startDateMs && activityMs <= endMs) {
      count += 1;
    }
  }
  return count;
}

function normalizeWalletProfileActivityFields(payload = {}) {
  const safePayload = payload && typeof payload === "object" ? { ...payload } : {};
  const safeSummary =
    safePayload.summary && typeof safePayload.summary === "object"
      ? { ...safePayload.summary }
      : null;
  const canonicalActivityAt = resolveWalletLastOpenedAt(safePayload);
  const normalizedActivityAt =
    Number.isFinite(canonicalActivityAt) && canonicalActivityAt > 0 ? canonicalActivityAt : null;
  if (!normalizedActivityAt) return safePayload;
  if (safeSummary) {
    safeSummary.lastOpenedAt = normalizedActivityAt;
    safeSummary.lastActivityAt = normalizedActivityAt;
    safeSummary.lastActivity = normalizedActivityAt;
    safePayload.summary = safeSummary;
  }
  safePayload.lastOpenedAt = normalizedActivityAt;
  safePayload.lastActivityAt = normalizedActivityAt;
  safePayload.lastActivity = normalizedActivityAt;
  return safePayload;
}

function resolveWalletLastOpenedAt(payload = {}, fallbackRecord = null) {
  const safePayload = payload && typeof payload === "object" ? payload : {};
  const safeSummary =
    safePayload.summary && typeof safePayload.summary === "object" ? safePayload.summary : null;
  const safeRecord = fallbackRecord && typeof fallbackRecord === "object" ? fallbackRecord : null;
  const wallet = String(
    safePayload.wallet ||
      safeSummary?.wallet ||
      (safeRecord && safeRecord.wallet) ||
      ""
  ).trim();
  const positionRows = Array.isArray(safePayload.positions)
    ? safePayload.positions
    : Array.isArray(safePayload.positions && safePayload.positions.positions)
    ? safePayload.positions.positions
    : [];
  const positionOpenedAt = positionRows.reduce((max, row) => {
    const openedAt = Number(row && row.openedAt ? row.openedAt : 0) || 0;
    return openedAt > max ? openedAt : max;
  }, 0);
  const fallbackOpenedAt = safeRecord
    ? Math.max(
        Number(safeRecord.lastOpenedAt || 0),
        Number(safeRecord.lastOpenedPosition && safeRecord.lastOpenedPosition.openedAt ? safeRecord.lastOpenedPosition.openedAt : 0),
        Number(safeRecord.all && safeRecord.all.lastOpenedAt ? safeRecord.all.lastOpenedAt : 0),
        Number(safeRecord.d30 && safeRecord.d30.lastOpenedAt ? safeRecord.d30.lastOpenedAt : 0),
        Number(safeRecord.d7 && safeRecord.d7.lastOpenedAt ? safeRecord.d7.lastOpenedAt : 0),
        Number(safeRecord.d24 && safeRecord.d24.lastOpenedAt ? safeRecord.d24.lastOpenedAt : 0)
      )
    : 0;
  const isolatedOpenedAt = wallet ? Number(loadWalletExplorerIsolatedOpenedAt(wallet) || 0) : 0;
  return (
    Number(
      (safeSummary && safeSummary.lastOpenedAt) ||
        (safeSummary && safeSummary.lastOpenedPosition && safeSummary.lastOpenedPosition.openedAt) ||
        safePayload.lastOpenedAt ||
        (safePayload.lastOpenedPosition && safePayload.lastOpenedPosition.openedAt) ||
        positionOpenedAt ||
        fallbackOpenedAt ||
        isolatedOpenedAt ||
        0
    ) || null
  );
}

function loadNextgenExchangeWalletMetrics() {
  try {
    const state = loadNextgenState();
    const walletMap =
      state && state.wallets && typeof state.wallets === "object" ? state.wallets : {};
    const tradesMap =
      state && state.trades && typeof state.trades === "object" ? state.trades : {};
    const liveMap =
      state && state.live && typeof state.live === "object" ? state.live : {};
    const walletRows = Object.values(walletMap);
    const v3Snapshot = loadWalletExplorerV3Snapshot();
    const v3Rows = Array.isArray(v3Snapshot && v3Snapshot.rows) ? v3Snapshot.rows : [];
    const historySnapshot = loadExchangeWalletMetricHistorySnapshot();
    const historyDailyByDate =
      historySnapshot &&
      historySnapshot.dailyByDate &&
      typeof historySnapshot.dailyByDate === "object" &&
      !Array.isArray(historySnapshot.dailyByDate)
        ? historySnapshot.dailyByDate
        : {};
    const historyCoverage =
      historySnapshot && historySnapshot.coverage && typeof historySnapshot.coverage === "object"
        ? historySnapshot.coverage
        : {};
    const trackedThroughDate =
      historyCoverage.endDate && String(historyCoverage.endDate).trim()
        ? String(historyCoverage.endDate).slice(0, 10)
        : getLastDateKeyFromDateMap(historyDailyByDate);
    const trackedThroughRow =
      trackedThroughDate && historyDailyByDate[trackedThroughDate]
        ? historyDailyByDate[trackedThroughDate]
        : null;
    const walletRowsWithState = walletRows.length;
    const walletExplorerRows = v3Rows.length ? v3Rows : walletRows;

    const sumWalletRows = (selector) =>
      walletExplorerRows.reduce((acc, row) => acc + toNum(selector(row), 0), 0);
    const countWalletRowsOnDate = (dateKey) => {
      if (!dateKey) return 0;
    return walletExplorerRows.reduce((acc, row) => {
      const ts = toNum(
        row &&
          (row.lastOpenedAt ||
            row.lastOpenedPositionAt ||
            row.lastPositionOpenedAt ||
            row.positionOpenedAt),
        0
      );
      return ts > 0 && formatUtcDateFromMs(ts) === dateKey ? acc + 1 : acc;
    }, 0);
  };

    const totalAccounts = pickFirstFiniteMetricValue(
      historyCoverage.totalAccounts,
      walletExplorerRows.length,
      walletRows.length
    );
    const activeWallets24h = pickFirstFiniteMetricValue(
      countWalletRowsOnDate(trackedThroughDate),
      trackedThroughRow && trackedThroughRow.activeWallets,
      trackedThroughDate
        ? resolveDailyMetricValueAtDate(historyDailyByDate, trackedThroughDate, (row) =>
            row && row.activeWallets !== undefined ? row.activeWallets : row && row.value
          )
        : 0
    );
    const totalTrades = pickFirstFiniteMetricValue(
      trackedThroughDate
        ? resolveDailyMetricValueAtDate(historyDailyByDate, trackedThroughDate, (row) =>
            row && row.trades !== undefined ? row.trades : 0
          )
        : historyCoverage.totalTrades,
      historyCoverage.totalTrades,
      sumWalletRows((row) => row && row.trades),
      walletRows.reduce((acc, row) => {
        const wallet = String(row && row.wallet ? row.wallet : "").trim();
        if (!wallet) return acc;
        const trade = tradesMap[wallet] && typeof tradesMap[wallet] === "object" ? tradesMap[wallet] : {};
        return acc + toNum(trade.trades !== undefined ? trade.trades : row.trades, 0);
      }, 0)
    );
    const totalVolumeUsd = pickFirstFiniteMetricValue(
      historyCoverage.totalVolumeUsd,
      sumWalletRows((row) => row && (row.volumeUsd !== undefined ? row.volumeUsd : row.volumeUsdRaw)),
      walletRows.reduce((acc, row) => {
        const wallet = String(row && row.wallet ? row.wallet : "").trim();
        if (!wallet) return acc;
        const trade = tradesMap[wallet] && typeof tradesMap[wallet] === "object" ? tradesMap[wallet] : {};
        return acc + toNum(
          trade.volume_usd !== undefined ? trade.volume_usd : row.volume_usd,
          0
        );
      }, 0)
    );
    const totalFeesUsd = pickFirstFiniteMetricValue(
      historyCoverage.totalFeesUsd,
      sumWalletRows((row) =>
        toNum(
          row && row.feesPaidUsd !== undefined
            ? row.feesPaidUsd
            : row && row.feesUsd !== undefined
            ? row.feesUsd
            : 0,
          0
        ) + toNum(row && row.liquidityPoolFeesUsd, 0)
      ),
      walletRows.reduce((acc, row) => {
        const feesUsd = toNum(
          row && row.fees_paid_usd !== undefined
            ? row.fees_paid_usd
            : row && row.fees_usd !== undefined
            ? row.fees_usd
            : 0,
          0
        );
        const liquidityPoolFeesUsd = toNum(row && row.liquidity_pool_fees_usd, 0);
        return acc + feesUsd + liquidityPoolFeesUsd;
      }, 0)
    );
    let minFirstTrade = Infinity;
    let maxCoverage = 0;
    walletExplorerRows.forEach((row) => {
      const firstTrade = toNum(row && row.firstTrade, 0);
      const lastTrade = toNum(row && row.lastTrade, 0);
      const lastActivity = Math.max(
        toNum(row && row.lastActivityAt, 0),
        toNum(row && row.lastActivity, 0),
        lastTrade,
        0
      );
      if (firstTrade > 0) {
        minFirstTrade = Math.min(minFirstTrade, firstTrade);
      }
      if (lastActivity > 0) {
        maxCoverage = Math.max(maxCoverage, lastActivity);
      }
    });
    const historyCoverageEndMs =
      trackedThroughDate && Number.isFinite(Date.parse(`${trackedThroughDate}T00:00:00.000Z`))
        ? Date.parse(`${trackedThroughDate}T00:00:00.000Z`)
        : 0;

    return {
      generatedAt: Math.max(
        toNum(state && state.meta && state.meta.generatedAt, 0),
        historyCoverageEndMs,
        maxCoverage,
        0
      ),
      totalAccounts,
      activeWallets24h,
      totalTrades,
      totalVolumeUsd,
      totalFeesUsd,
      coverageStartMs: Number.isFinite(minFirstTrade) ? minFirstTrade : null,
      coverageEndMs: historyCoverageEndMs || (maxCoverage > 0 ? maxCoverage : null),
      walletsWithState: walletRowsWithState || walletExplorerRows.length,
    };
  } catch (_error) {
    return null;
  }
}

function buildMetricCompletenessState({
  available = true,
  partial = false,
  estimated = false,
  exact = false,
} = {}) {
  if (!available) return "unavailable";
  if (exact) return "exact";
  if (estimated) return "estimated";
  if (partial) return "partial";
  return "partial";
}

function buildMetricDescriptor({
  key,
  label,
  value,
  state,
  method,
  source,
  coverageStartDate = null,
  coverageEndDate = null,
  completeThroughDate = null,
  note = null,
} = {}) {
  return {
    key: key || null,
    label: label || key || null,
    value:
      value !== undefined && value !== null && Number.isFinite(Number(value))
        ? Number(value)
        : null,
    state: buildMetricCompletenessState({
      available: state !== "unavailable",
      partial: state === "partial",
      estimated: state === "estimated",
      exact: state === "exact",
    }),
    method: method || "derived",
    source: source || null,
    coverage: {
      startDate: coverageStartDate || null,
      endDate: coverageEndDate || null,
      completeThroughDate: completeThroughDate || null,
    },
    note: note || null,
  };
}

function buildWalletPerformanceSupportSummary({
  walletMetricsHistoryStatus = null,
  positionLifecycleStatus = null,
} = {}) {
  const historyStatus = walletMetricsHistoryStatus;
  const lifecycleStatus = positionLifecycleStatus;
  const available = [
    {
      key: "recent_trade_count",
      label: "Recent trade count",
      source: "wallet trade history",
    },
    {
      key: "recent_volume",
      label: "Recent traded volume",
      source: "wallet trade history",
    },
    {
      key: "realized_pnl",
      label: "Realized PnL",
      source: "wallet trade history",
    },
    {
      key: "unrealized_pnl",
      label: "Unrealized PnL",
      source: "live open positions",
    },
    {
      key: "total_pnl",
      label: "Total PnL",
      source: "wallet trade history + live open positions",
    },
    {
      key: "win_rate",
      label: "Win rate",
      source: "wallet trade history",
    },
    {
      key: "open_positions",
      label: "Open positions count",
      source: "wallet-first live positions",
    },
    {
      key: "exposure",
      label: "Current exposure",
      source: "wallet-first live positions",
    },
    {
      key: "symbol_concentration",
      label: "Symbol concentration",
      source: "wallet trade history",
    },
    {
      key: "recent_activity_score",
      label: "Recent activity score",
      source: "live wallet events + open positions",
    },
    {
      key: "live_active_score",
      label: "Live active score",
      source: "derived from live activity + exposure",
    },
    {
      key: "freshness_state",
      label: "Freshness / last update state",
      source: "live scan timestamps",
    },
  ];
  const unavailable = [];

  if (historyStatus && Number(historyStatus.hourlyFiles || 0) > 0) {
    available.push({
      key: "hourly_wallet_snapshots",
      label: "Hourly wallet snapshots",
      source: "persisted hourly wallet aggregate snapshot store",
    });
  } else {
    unavailable.push({
      key: "hourly_wallet_snapshots",
      label: "Hourly wallet snapshots",
      reason: "Rolling wallet snapshots are not persisted today.",
      required: "Hourly aggregate snapshot store.",
    });
  }

  if (historyStatus && Number(historyStatus.dailyFiles || 0) > 0) {
    available.push({
      key: "daily_wallet_snapshots",
      label: "Daily wallet snapshots",
      source: "persisted daily wallet aggregate snapshot store",
    });
  } else {
    unavailable.push({
      key: "daily_wallet_snapshots",
      label: "Daily wallet snapshots",
      reason: "Daily wallet performance aggregates are recomputed from history, not snapshotted.",
      required: "Daily wallet aggregate snapshot store.",
    });
  }

  if (lifecycleStatus && Number(lifecycleStatus.trackedPositions || 0) > 0) {
    available.push({
      key: "position_change_history",
      label: "Position increase / reduce history",
      source: "observed position lifecycle store",
      scope: "observed_from_tracking_start",
    });
    available.push({
      key: "position_holding_time",
      label: "Position holding time",
      source: "live position age + observed position lifecycle store",
      scope: "observed_from_tracking_start",
    });
    available.push({
      key: "wallet_holding_time",
      label: "Wallet holding time",
      source: "observed position lifecycle store",
      scope: "observed_from_tracking_start",
    });
  } else {
    unavailable.push({
      key: "wallet_holding_time",
      label: "Wallet holding time",
      reason: "Wallet snapshots do not persist entry/exit duration history.",
      required: "Wallet-level snapshot history with entry/exit timestamps.",
    });
    unavailable.push({
      key: "position_holding_time",
      label: "Position holding time",
      reason: "Position lifecycle events are not persisted historically per wallet.",
      required: "Explicit position lifecycle history with open/increase/reduce/close events.",
    });
    unavailable.push({
      key: "position_change_history",
      label: "Position increase / reduce history",
      reason: "Historical position state transitions are not materialized yet.",
      required: "Versioned position snapshots or lifecycle event log.",
    });
  }

  return {
    windows: ["24h", "7d", "30d", "all"],
    available,
    unavailable,
    status: {
      walletMetricsHistory: historyStatus || { enabled: false },
      positionLifecycle: lifecycleStatus || { enabled: false },
    },
  };
}

function buildKpiComparisonEntry({
  currentValue,
  baselineValue = null,
  comparisonLabel = "",
  fallbackLabel = "snapshot",
}) {
  const current = toNum(currentValue, 0);
  const baseline = toNum(baselineValue, NaN);
  if (!Number.isFinite(baseline) || baseline <= 0) {
    return {
      trend: "flat",
      deltaAbs: null,
      deltaPct: null,
      comparisonLabel: fallbackLabel,
      baselineValue: null,
      currentValue: current,
      comparisonAvailable: false,
    };
  }

  const deltaAbs = current - baseline;
  const deltaPct = baseline !== 0 ? (deltaAbs / baseline) * 100 : null;
  const trend =
    Math.abs(deltaAbs) < Math.max(1e-9, Math.abs(baseline) * 0.0005)
      ? "flat"
      : deltaAbs > 0
        ? "up"
        : "down";

  return {
    trend,
    deltaAbs,
    deltaPct,
    comparisonLabel,
    baselineValue: baseline,
    currentValue: current,
    comparisonAvailable: true,
  };
}

function normalizeComparisonEntryCurrentValue(entry = {}, currentValue = 0) {
  const current = toNum(currentValue, 0);
  const deltaPct = toNum(entry && entry.deltaPct, NaN);
  const deltaAbs = toNum(entry && entry.deltaAbs, NaN);
  const next = {
    ...(entry && typeof entry === "object" ? entry : {}),
    currentValue: current,
  };
  if (Number.isFinite(deltaPct)) {
    const denominator = 1 + deltaPct / 100;
    if (Math.abs(denominator) > 1e-9) {
      const baselineValue = current / denominator;
      next.baselineValue = baselineValue;
      next.deltaAbs = current - baselineValue;
      next.deltaPct = deltaPct;
      return next;
    }
  }
  if (Number.isFinite(deltaAbs)) {
    next.baselineValue = current - deltaAbs;
    return next;
  }
  return {
    ...next,
  };
}

function buildAbsoluteKpiChangeEntry({
  currentValue,
  deltaAbs = null,
  baselineValue = null,
  comparisonLabel = "",
  fallbackLabel = "snapshot",
  displayMode = "absolute",
}) {
  const current = toNum(currentValue, 0);
  const delta =
    deltaAbs === null || deltaAbs === undefined || deltaAbs === ""
      ? NaN
      : toNum(deltaAbs, NaN);
  const baseline =
    baselineValue === null || baselineValue === undefined || baselineValue === ""
      ? NaN
      : toNum(baselineValue, NaN);
  if (!Number.isFinite(delta)) {
    return {
      trend: "flat",
      deltaAbs: null,
      deltaPct: null,
      comparisonLabel: comparisonLabel || fallbackLabel,
      baselineValue: Number.isFinite(baseline) ? baseline : null,
      currentValue: current,
      comparisonAvailable: false,
      displayMode,
    };
  }

  const trend = Math.abs(delta) < 1e-9 ? "flat" : delta > 0 ? "up" : "down";
  const deltaPct = Number.isFinite(baseline) && Math.abs(baseline) > 1e-9
    ? (delta / Math.abs(baseline)) * 100
    : null;

  return {
    trend,
    deltaAbs: delta,
    deltaPct,
    comparisonLabel: comparisonLabel || fallbackLabel,
    baselineValue: Number.isFinite(baseline) ? baseline : null,
    currentValue: current,
    comparisonAvailable: true,
    displayMode,
  };
}

function buildExchangeKpiComparisons({
  timeframe = "all",
  walletWindows = {},
  volumeWindows = {},
  openInterestUsd = 0,
  walletCoverageDays = null,
  volumeCoverageDays = null,
}) {
  const tf = String(timeframe || "all").toLowerCase();
  const allWallets = walletWindows.all || {};
  const window24h = walletWindows["24h"] || {};
  const window30d = walletWindows["30d"] || {};
  const volume24h = volumeWindows["24h"] || {};
  const volume30d = volumeWindows["30d"] || {};
  const volumeAll = volumeWindows.all || {};

  if (tf === "24h") {
    return {
      timeframe: tf,
      metrics: {
        totalAccounts: {
          trend: "flat",
          deltaAbs: null,
          deltaPct: null,
          comparisonLabel: "active accounts",
          baselineValue: null,
          currentValue: toNum(window24h.activeAccounts, 0),
          comparisonAvailable: false,
        },
        totalTrades: buildKpiComparisonEntry({
          currentValue: window24h.totalTrades,
          baselineValue: toNum(window30d.totalTrades, 0) / 30,
          comparisonLabel: "vs 30d avg/day",
          fallbackLabel: "24h window",
        }),
        totalVolumeUsd: buildKpiComparisonEntry({
          currentValue: volume24h.totalVolumeUsd,
          baselineValue: toNum(volume30d.totalVolumeUsd, 0) / 30,
          comparisonLabel: "vs 30d avg/day",
          fallbackLabel: "24h window",
        }),
        totalFeesUsd: buildKpiComparisonEntry({
          currentValue: window24h.totalFeesUsd,
          baselineValue: toNum(window30d.totalFeesUsd, 0) / 30,
          comparisonLabel: "vs 30d avg/day",
          fallbackLabel: "24h window",
        }),
        openInterestAtEnd: {
          trend: "flat",
          deltaAbs: null,
          deltaPct: null,
          comparisonLabel: "historical delta unavailable",
          baselineValue: null,
          currentValue: toNum(openInterestUsd, 0),
          comparisonAvailable: false,
        },
      },
    };
  }

  if (tf === "30d") {
    const wallet30dBaseline =
      Number.isFinite(walletCoverageDays) && walletCoverageDays > 30
        ? (toNum(allWallets.totalTrades, 0) / walletCoverageDays) * 30
        : null;
    const wallet30dFeesBaseline =
      Number.isFinite(walletCoverageDays) && walletCoverageDays > 30
        ? (toNum(allWallets.totalFeesUsd, 0) / walletCoverageDays) * 30
        : null;
    const volume30dBaseline =
      Number.isFinite(volumeCoverageDays) && volumeCoverageDays > 30
        ? (toNum(volumeAll.totalVolumeUsd, 0) / volumeCoverageDays) * 30
        : null;

    return {
      timeframe: tf,
      metrics: {
        totalAccounts: {
          trend: "flat",
          deltaAbs: null,
          deltaPct: null,
          comparisonLabel: "active accounts",
          baselineValue: null,
          currentValue: toNum(window30d.activeAccounts, 0),
          comparisonAvailable: false,
        },
        totalTrades: buildKpiComparisonEntry({
          currentValue: window30d.totalTrades,
          baselineValue: wallet30dBaseline,
          comparisonLabel: "vs lifetime 30d run rate",
          fallbackLabel: "30d window",
        }),
        totalVolumeUsd: buildKpiComparisonEntry({
          currentValue: volume30d.totalVolumeUsd,
          baselineValue: volume30dBaseline,
          comparisonLabel: "vs lifetime 30d run rate",
          fallbackLabel: "30d window",
        }),
        totalFeesUsd: buildKpiComparisonEntry({
          currentValue: window30d.totalFeesUsd,
          baselineValue: wallet30dFeesBaseline,
          comparisonLabel: "vs lifetime 30d run rate",
          fallbackLabel: "30d window",
        }),
        openInterestAtEnd: {
          trend: "flat",
          deltaAbs: null,
          deltaPct: null,
          comparisonLabel: "historical delta unavailable",
          baselineValue: null,
          currentValue: toNum(openInterestUsd, 0),
          comparisonAvailable: false,
        },
      },
    };
  }

  return {
    timeframe: tf,
    metrics: {
      totalAccounts: {
        trend: "flat",
        deltaAbs: null,
        deltaPct: null,
        comparisonLabel: "active accounts",
        baselineValue: null,
        currentValue: toNum(allWallets.activeAccounts, 0),
        comparisonAvailable: false,
      },
      totalTrades: {
        trend: "flat",
        deltaAbs: null,
        deltaPct: null,
        comparisonLabel: "lifetime total",
        baselineValue: null,
        currentValue: toNum(allWallets.totalTrades, 0),
        comparisonAvailable: false,
      },
      totalVolumeUsd: {
        trend: "flat",
        deltaAbs: null,
        deltaPct: null,
        comparisonLabel: "lifetime total",
        baselineValue: null,
        currentValue: toNum(volumeAll.totalVolumeUsd, 0),
        comparisonAvailable: false,
      },
      totalFeesUsd: {
        trend: "flat",
        deltaAbs: null,
        deltaPct: null,
        comparisonLabel: "lifetime total",
        baselineValue: null,
        currentValue: toNum(allWallets.totalFeesUsd, 0),
        comparisonAvailable: false,
      },
      openInterestAtEnd: {
        trend: "flat",
        deltaAbs: null,
        deltaPct: null,
        comparisonLabel: "historical delta unavailable",
        baselineValue: null,
        currentValue: toNum(openInterestUsd, 0),
        comparisonAvailable: false,
      },
    },
  };
}

function extractPayloadData(result, fallback = null) {
  if (!result || !result.payload) return fallback;
  if (Object.prototype.hasOwnProperty.call(result.payload, "data")) {
    return result.payload.data;
  }
  return result.payload;
}

function normalizeTokenSymbol(value) {
  return String(value || "")
    .trim()
    .toUpperCase()
    .replace(/[^A-Z0-9/_-]/g, "");
}

function buildTokenSymbolCandidates(symbol) {
  const normalized = normalizeTokenSymbol(symbol);
  if (!normalized) return [];
  const compact = normalized.replace(/[^A-Z0-9]/g, "");
  const noPerp = compact.replace(/PERP$/, "");
  const noUsd = noPerp.replace(/USDT$/, "").replace(/USD$/, "");
  return Array.from(new Set([normalized, compact, noPerp, noUsd].filter(Boolean)));
}

function findPriceRowForSymbol(rows = [], symbol) {
  const byCandidate = new Map();
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const rowSymbol = normalizeTokenSymbol(row && row.symbol);
    if (!rowSymbol) return;
    buildTokenSymbolCandidates(rowSymbol).forEach((candidate) => {
      if (!byCandidate.has(candidate)) byCandidate.set(candidate, row);
    });
  });
  const candidates = buildTokenSymbolCandidates(symbol);
  for (const candidate of candidates) {
    if (byCandidate.has(candidate)) return byCandidate.get(candidate);
  }
  return null;
}

function toTradeTimestampMs(row = {}) {
  const candidates = [
    row.timestamp,
    row.t,
    row.createdAt,
    row.created_at,
    row.updatedAt,
    row.updated_at,
  ];
  for (const candidate of candidates) {
    const ts = Number(candidate);
    if (!Number.isFinite(ts) || ts <= 0) continue;
    // Normalize second-based timestamps to ms.
    return ts < 1e12 ? ts * 1000 : ts;
  }
  return NaN;
}

function normalizeTradeSide(side) {
  return String(side || "")
    .trim()
    .toLowerCase()
    .replace(/[\s-]+/g, "_");
}

function toNotionalUsd(row = {}) {
  const rawNotional = row.notional !== undefined ? row.notional : row.notional_usd;
  const asNumber = Number(rawNotional);
  if (Number.isFinite(asNumber) && asNumber > 0) return Math.abs(asNumber);
  const amount = Number(row.amount !== undefined ? row.amount : row.a);
  const price = Number(row.price !== undefined ? row.price : row.p);
  if (!Number.isFinite(amount) || !Number.isFinite(price)) return 0;
  return Math.abs(amount * price);
}

function normalizePublicTradeRow(row = {}) {
  return {
    historyId: row.history_id || row.historyId || row.h || null,
    symbol: normalizeTokenSymbol(row.symbol || row.s || ""),
    side: normalizeTradeSide(row.side || row.d || ""),
    cause: String(row.cause || row.tc || "").toLowerCase(),
    amount: Number(row.amount !== undefined ? row.amount : row.a),
    price: Number(row.price !== undefined ? row.price : row.p),
    timestamp: toTradeTimestampMs(row),
    notionalUsd: toNotionalUsd(row),
  };
}

function normalizeFundingHistoryRow(row = {}) {
  const createdAtRaw =
    row.created_at !== undefined ? row.created_at : row.createdAt !== undefined ? row.createdAt : row.t;
  const createdAt = toTradeTimestampMs({ timestamp: createdAtRaw });
  const alreadyPct = Number(row.fundingRatePct);
  if (Number.isFinite(alreadyPct)) {
    return {
      createdAt,
      fundingRatePct: alreadyPct,
    };
  }
  const fundingRateRaw =
    row.funding_rate !== undefined
      ? row.funding_rate
      : row.fundingRate !== undefined
      ? row.fundingRate
      : row.funding;
  const fundingRate = Number(fundingRateRaw);
  return {
    createdAt,
    fundingRatePct: Number.isFinite(fundingRate) ? fundingRate * 100 : NaN,
  };
}

function isLiquidationCause(cause) {
  const normalized = String(cause || "").toLowerCase();
  return (
    normalized.includes("liq") ||
    normalized.includes("liquid") ||
    normalized === "market_liquidation"
  );
}

function getWalletMetricDayRow(walletMetricDailyByDate = {}, walletMetricTrackedThroughDate = null) {
  const dailyByDate =
    walletMetricDailyByDate && typeof walletMetricDailyByDate === "object"
      ? walletMetricDailyByDate
      : {};
  const trackedThroughDate =
    walletMetricTrackedThroughDate && String(walletMetricTrackedThroughDate).trim()
      ? String(walletMetricTrackedThroughDate).slice(0, 10)
      : null;
  return trackedThroughDate && dailyByDate[trackedThroughDate] ? dailyByDate[trackedThroughDate] : null;
}

function classifyNetflowSign(side) {
  const normalized = normalizeTradeSide(side);
  if (!normalized) return 0;
  if (
    normalized === "buy" ||
    normalized === "b" ||
    normalized === "open_long" ||
    normalized === "close_short"
  ) {
    return 1;
  }
  if (
    normalized === "sell" ||
    normalized === "s" ||
    normalized === "open_short" ||
    normalized === "close_long"
  ) {
    return -1;
  }
  return 0;
}

function classifyLiquidationBucket(side) {
  const normalized = normalizeTradeSide(side);
  if (!normalized) return "unknown";
  // Long liquidations close long risk (typically sell / close_long / open_short prints).
  if (
    normalized === "sell" ||
    normalized === "s" ||
    normalized === "close_long" ||
    normalized === "open_short"
  ) {
    return "long";
  }
  // Short liquidations close short risk (typically buy / close_short / open_long prints).
  if (
    normalized === "buy" ||
    normalized === "b" ||
    normalized === "close_short" ||
    normalized === "open_long"
  ) {
    return "short";
  }
  return "unknown";
}

function dedupeBy(rows = [], keyFn) {
  const seen = new Set();
  const out = [];
  (Array.isArray(rows) ? rows : []).forEach((row) => {
    const key = keyFn(row);
    if (!key || seen.has(key)) return;
    seen.add(key);
    out.push(row);
  });
  return out;
}

function normalizeHistoryIdKey(value) {
  if (value === null || value === undefined) return "";
  const raw = String(value).trim();
  return raw || "";
}

