          const mergedUnrealizedCandidate = toNum(pickUnrealizedPnlUsdFromRow(live), NaN);
          const mergedUnrealizedFallback = toNum(pickUnrealizedPnlUsdFromSummary(base), NaN);
          const mergedUnrealizedStrict = toNum(pickUnrealizedPnlUsdFromSummary(strictLive), NaN);
