    const account =
      baselineWalletSummary && typeof baselineWalletSummary === "object"
        ? baselineWalletSummary
        : walletSeed && typeof walletSeed === "object"
        ? walletSeed
        : null;
    const liveSnapshot = includeLiveSnapshot ? getLiveWalletSnapshot(50) : null;
    const sharedTradeSummary = getSharedWalletTradeSummaryRow(normalizedWallet);
    const recentTradesPayload = includeRecentTrades
      ? getSharedWalletRecentTrades(normalizedWallet, { limit: 100, offset: 0 })
      : { generatedAt: Date.now(), summary: null, total: 0, rows: [] };
    const liveStates = (
      liveSnapshot && Array.isArray(liveSnapshot.liveStates) ? liveSnapshot.liveStates : []
    ).filter((row) => String((row && row.wallet) || "").trim() === normalizedWallet);
    const liveEvents = (
      liveSnapshot && Array.isArray(liveSnapshot.events) ? liveSnapshot.events : []
    ).filter((row) => String((row && row.wallet) || "").trim() === normalizedWallet);
