      const compactSnapshot = loadWalletExplorerCompactSnapshotFromDisk();
      const compactRows =
        compactSnapshot && Array.isArray(compactSnapshot.preparedRows)
          ? compactSnapshot.preparedRows
          : compactSnapshot && Array.isArray(compactSnapshot.rows)
          ? compactSnapshot.rows
          : [];
