          method: "derived",
          source:
            timeframe === "30d"
              ? "wallet_explorer_v3:lastTrade lookback 30d"
              : "wallet_explorer_v3:lastTrade lookback 24h",
          coverageStartDate: walletMetricStartDate || walletCoverage.startDate,
          coverageEndDate: walletMetricTrackedThroughDate || walletCoverage.endDate,
          completeThroughDate:
            walletBackfillComplete ? (walletMetricTrackedThroughDate || walletCoverage.endDate) : null,
          note:
            activeWalletsValue <= 0
