      const exchangeVolumeUsd = toNum(payload.kpis && payload.kpis.totalVolumeUsd, 0);
      const walletRawVolumeUsd = toNum(
        walletWindowMetrics && walletWindowMetrics[timeframe]
          ? walletWindowMetrics[timeframe].totalVolumeUsd
          : 0,
        0
      );
      const walletVerifiedVolumeUsd = toNum(
        verifiedWalletWindowMetrics && verifiedWalletWindowMetrics[timeframe]
          ? verifiedWalletWindowMetrics[timeframe].totalVolumeUsd
          : 0,
        0
      );
      const walletHistoryVerifiedVolumeUsd = toNum(
        historyVerifiedWalletWindowMetrics && historyVerifiedWalletWindowMetrics[timeframe]
          ? historyVerifiedWalletWindowMetrics[timeframe].totalVolumeUsd
          : 0,
        0
      );
      const retryPendingWalletVolumeUsd = toNum(
        retryPendingWalletWindowMetrics && retryPendingWalletWindowMetrics[timeframe]
          ? retryPendingWalletWindowMetrics[timeframe].totalVolumeUsd
          : 0,
        0
      );
      const rawGapUsd = exchangeVolumeUsd - walletRawVolumeUsd;
      const verifiedGapUsd = exchangeVolumeUsd - walletVerifiedVolumeUsd;
      const reconciliationReasons = [];
